endpoints.typeql:
match $a isa tech-recon-analysis, has id ":aid";
fetch {
    "id": $a.id,
    "title": $a.tech-recon-title,
    "type": $a.analysis-type,
    "plot_code": $a.plot-code,
    "query": $a.tql-query,
    "description": $a.content
};

# Investigation details
match $inv isa tech-recon-investigation, has id ":id";
fetch {
    "id": $inv.id,
    "name": $inv.name,
    "status": $inv.tech-recon-status,
    "goal": $inv.goal-description,
    "criteria": $inv.success-criteria,
    "iteration": $inv.iteration-number
};

# Systems in investigation
match
    $inv isa tech-recon-investigation, has id ":id";
    $sys isa tech-recon-system;
    (system: $sys, investigation: $inv) isa investigated-in;
fetch {
    "id": $sys.id,
    "name": $sys.name,
    "url": $sys.tech-recon-url,
    "status": $sys.tech-recon-status,
    "language": $sys.tech-recon-language,
    "license": $sys.license,
    "star_count": $sys.star-count
};

# Notes attached to investigation
match
    $e isa identifiable-entity, has id ":id";
    $n isa tech-recon-note;
    (note: $n, subject: $e) isa aboutness;
fetch {
    "id": $n.id,
    "topic": $n.topic,
    "format": $n.format,
    "content": $n.content,
    "created_at": $n.created-at
};

# Analyses linked to investigation
match
    $inv isa tech-recon-investigation, has id ":id";
    $a isa tech-recon-analysis;
    (analysis: $a, investigation: $inv) isa analysis-of;
fetch {
    "id": $a.id,
    "title": $a.tech-recon-title,
    "type": $a.analysis-type
};

# System details
match $sys isa tech-recon-system, has id ":id";
fetch {
    "id": $sys.id,
    "name": $sys.name,
    "url": $sys.tech-recon-url,
    "status": $sys.tech-recon-status,
    "github_url": $sys.github-url,
    "language": $sys.tech-recon-language,
    "license": $sys.license,
    "star_count": $sys.star-count
};

# Artifacts sourced from system
match
    $sys isa tech-recon-system, has id ":id";
    $art isa tech-recon-artifact;
    (artifact: $art, source: $sys) isa sourced-from;
fetch {
    "id": $art.id,
    "type": $art.artifact-type,
    "url": $art.tech-recon-url,
    "format": $art.format,
    "cache_path": $art.cache-path
};

# Notes about system
match
    $e isa identifiable-entity, has id ":id";
    $n isa tech-recon-note;
    (note: $n, subject: $e) isa aboutness;
fetch {
    "id": $n.id,
    "topic": $n.topic,
    "format": $n.format,
    "content": $n.content,
    "created_at": $n.created-at
};

match $art isa tech-recon-artifact, has id ":id";
fetch {
    "id": $art.id,
    "type": $art.artifact-type,
    "url": $art.tech-recon-url,
    "format": $art.format,
    "cache_path": $art.cache-path
};
